import{_ as t,c as r,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Architektur: Agent Skills | Agent Skills","description":"Verstehen Sie die technische Architektur von Agent Skills. Lernen Sie Build-Ablauf, Regelparser, Typensystem und Deployment-Mechanismen.","frontmatter":{"title":"Architektur: Agent Skills | Agent Skills","sidebarTitle":"Architektur","subtitle":"Architektur: Agent Skills","description":"Verstehen Sie die technische Architektur von Agent Skills. Lernen Sie Build-Ablauf, Regelparser, Typensystem und Deployment-Mechanismen.","tags":["Architektur","Build-Ablauf","Regelparsing","Typensystem"],"prerequisite":["start-getting-started"]},"headers":[],"relativePath":"de/vercel-labs/agent-skills/appendix/architecture/index.md","filePath":"de/vercel-labs/agent-skills/appendix/architecture/index.md"}'),d={name:"de/vercel-labs/agent-skills/appendix/architecture/index.md"};function a(l,e,s,o,c,u){return i(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="architektur-und-implementationsdetails" tabindex="-1">Architektur und Implementationsdetails <a class="header-anchor" href="#architektur-und-implementationsdetails" aria-label="Permalink to &quot;Architektur und Implementationsdetails&quot;">​</a></h1><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><ul><li>Verstehen Sie die Funktionsweise der Agent Skills Build-Toolchain</li><li>Beherrschen Sie die Kernlogik des Regeldatei-Parsings</li><li>Verstehen Sie das Typensystem und das Datenflussdesign</li><li>Lernen Sie die Implementierungsdetails der Framework-Erkennungsalgorithmen</li></ul><h2 id="kernarchitektur-ubersicht" tabindex="-1">Kernarchitektur-Übersicht <a class="header-anchor" href="#kernarchitektur-ubersicht" aria-label="Permalink to &quot;Kernarchitektur-Übersicht&quot;">​</a></h2><p>Agent Skills besteht aus drei Hauptteilen:</p><p><strong>1. Build-Toolchain</strong> (<code>packages/react-best-practices-build/</code>)</p><ul><li>Regeldateien parsen</li><li>AGENTS.md generieren</li><li>Testfälle extrahieren</li></ul><p><strong>2. Regeldateien</strong> (<code>skills/react-best-practices/rules/</code>)</p><ul><li>57 React-Performance-Optimierungsregeln</li><li>Markdown-Format, folgt den Template-Spezifikationen</li></ul><p><strong>3. Deployment-Skripte</strong> (<code>skills/claude.ai/vercel-deploy-claimable/</code>)</p><ul><li>Ein-Klick-Deployment auf Vercel</li><li>Automatische Framework-Erkennung</li></ul><h2 id="build-ablauf-details" tabindex="-1">Build-Ablauf-Details <a class="header-anchor" href="#build-ablauf-details" aria-label="Permalink to &quot;Build-Ablauf-Details&quot;">​</a></h2><p>Der Build-Ablauf kompiliert die verteilten Regeldateien in eine AGENTS.md-Datei, die vom AIAgent gelesen werden kann. Der Ablauf ist in fünf Phasen unterteilt:</p><h3 id="phase-1-regeldateien-parsen" tabindex="-1">Phase 1: Regeldateien parsen <a class="header-anchor" href="#phase-1-regeldateien-parsen" aria-label="Permalink to &quot;Phase 1: Regeldateien parsen&quot;">​</a></h3><p>Jede Regeldatei (<code>.md</code>) wird durch die Funktion <code>parseRuleFile()</code> in ein <code>Rule</code>-Objekt geparst.</p><p><strong>Parsing-Reihenfolge</strong> (Quellcode-Position: <code>parser.ts:18-238</code>):</p><ol><li><p><strong>Frontmatter extrahieren</strong> (falls vorhanden)</p><ul><li>YAML-Format-Metadaten parsen</li><li>Unterstützte Felder: <code>title</code>, <code>impact</code>, <code>tags</code>, <code>section</code>, <code>explanation</code>, <code>references</code></li></ul></li><li><p><strong>Überschrift extrahieren</strong></p><ul><li>Erste <code>##</code> oder <code>###</code>-Überschrift suchen</li><li>Wenn Frontmatter keinen title hat, wird dieser Inhalt verwendet</li></ul></li><li><p><strong>Impact extrahieren</strong></p><ul><li>Zeile mit <code>**Impact:**</code> abgleichen</li><li>Format: <code>**Impact:** CRITICAL (2-10× improvement)</code></li><li>Level und Beschreibung extrahieren</li></ul></li><li><p><strong>Codebeispiele extrahieren</strong></p><ul><li>Markierungen mit <code>**Label:**</code> suchen (wie <code>**Incorrect:**</code>, <code>**Correct:**</code>)</li><li>Nachfolgende Codeblöcke sammeln</li><li>Ergänzungstexte nach dem Codeblock erfassen</li></ul></li><li><p><strong>Referenzen extrahieren</strong></p><ul><li>Zeile mit <code>Reference:</code> oder <code>References:</code> suchen</li><li>Markdown-Links <code>[text](url)</code> parsen</li></ul></li><li><p><strong>Section ableiten</strong></p><ul><li>Aus dem Dateinamenpräfix extrahieren (Quellcode-Position: <code>parser.ts:201-210</code>)</li></ul></li></ol><h2 id="typensystem" tabindex="-1">Typensystem <a class="header-anchor" href="#typensystem" aria-label="Permalink to &quot;Typensystem&quot;">​</a></h2><p>Typendefinitionen in <code>types.ts</code> (Quellcode-Position: <code>types.ts:1-54</code>).</p><h3 id="impactlevel-enumeration" tabindex="-1">ImpactLevel-Enumeration <a class="header-anchor" href="#impactlevel-enumeration" aria-label="Permalink to &quot;ImpactLevel-Enumeration&quot;">​</a></h3><p>Der Impact-Level identifiziert den Performance-Einflussgrad der Regel, mit 6 Levels:</p><table tabindex="0"><thead><tr><th>Wert</th><th>Beschreibung</th><th>Anwendbare Szenarien</th></tr></thead><tbody><tr><td><code>CRITICAL</code></td><td>Kritische Engpässe</td><td>müssen behoben werden, beeinträchtigt erheblich die User Experience (wie Wasserfälle, unoptimierte Bundle-Größen)</td></tr><tr><td><code>HIGH</code></td><td>Wichtige Verbesserungen</td><td>signifikante Performance-Steigerung (wie Server-Side-Caching, Beseitigung doppelter Props)</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td><code>MEDIUM</code></td><td>Mittlere Verbesserungen</td><td>messbare Performance-Verbesserung (wie Memo-Optimierung, Reduzierung von Re-renders)</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td><code>LOW</code></td><td>Inkrementelle Verbesserungen</td><td>Mikro-Optimierungen (wie Code-Stil, erweiterte Muster)</td></tr></tbody></table><h3 id="rule-interface" tabindex="-1">Rule-Interface <a class="header-anchor" href="#rule-interface" aria-label="Permalink to &quot;Rule-Interface&quot;">​</a></h3><p>Vollständige Struktur einer einzelnen Performance-Optimierungsregel:</p><table tabindex="0"><thead><tr><th>Feld</th><th>Typ</th><th>Pflicht</th><th>Beschreibung</th></tr></thead><tbody><tr><td><code>id</code></td><td>string</td><td>✅</td><td>Regel-ID (automatisch generiert, wie &quot;1.1&quot;, &quot;2.3&quot;)</td></tr><tr><td><code>title</code></td><td>string</td><td>✅</td><td>Regeltitel</td></tr><tr><td><code>section</code></td><td>number</td><td>✅</td><td>Zugehöriges Kapitel (1-8)</td></tr><tr><td><code>subsection</code></td><td>number</td><td>❌</td><td>Unterkapitelnr. (automatisch generiert)</td></tr><tr><td><code>impact</code></td><td>ImpactLevel</td><td>✅</td><td>Impact-Level</td></tr><tr><td><code>impactDescription</code></td><td>string</td><td>❌</td><td>Impact-Beschreibung (wie &quot;2-10× improvement&quot;)</td></tr><tr><td><code>explanation</code></td><td>string</td><td>✅</td><td>Regelerklärung</td></tr><tr><td><code>examples</code></td><td>CodeExample[]</td><td>✅</td><td>Array von Codebeispielen (mindestens 1)</td></tr><tr><td><code>references</code></td><td>string[]</td><td>❌</td><td>Referenz-Links</td></tr><tr><td><code>tags</code></td><td>string[]</td><td>❌</td><td>Tags (für Suche)</td></tr></tbody></table><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p><strong>Kernarchitektur</strong>:</p><ol><li><strong>Build-Toolchain</strong>: Parsen → Validieren → Gruppieren → Sortieren → Generieren</li><li><strong>Regelparser</strong>: Extrahiert Frontmatter, Überschriften, Impact, Beispiele, Referenzen</li><li><strong>Typensystem</strong>: ImpactLevel, Rule, CodeExample, Section, GuidelinesDocument, TestCase-Interfaces</li><li><strong>Testfall-Extraktion</strong>: Extrahiert bad/good-Beispiele aus Regeln für LLM-Bewertung</li></ol><p><strong>Nächste Schritte</strong>:</p><ul><li><a href="./../../advanced/skill-development/">Entwicklung benutzerdefinierter Skills</a></li><li><a href="./../../advanced/rule-authoring/">Erstellen von React Best Practices Regeln</a></li><li><a href="./../reference/">API- und Befehlsreferenz ansehen</a></li></ul><hr><h2 id="anhang-quellcodereferenz" tabindex="-1">Anhang: Quellcodereferenz <a class="header-anchor" href="#anhang-quellcodereferenz" aria-label="Permalink to &quot;Anhang: Quellcodereferenz&quot;">​</a></h2><details><summary><strong>Klicken zum Anzeigen der Quellcodepositionen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>Typensystem</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/src/types.ts" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/src/types.ts</code></a></td><td>1-54</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Regelparser</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/src/parser.ts" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/src/parser.ts</code></a></td><td>18-238</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>ImpactLevel</code>-Enum-Werte: CRITICAL, HIGH, MEDIUM-HIGH, MEDIUM, LOW-MEDIUM, LOW (<code>types.ts:5</code>)</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>parseRuleFile()</code>: Parst Markdown-Regeldatei in Rule-Objekt (<code>parser.ts:18</code>)</li><li><code>extractTestCases()</code>: Extrahiert Testfälle aus Regeln (<code>extract-tests.ts:15</code>)</li><li><code>generateMarkdown()</code>: Generiert AGENTS.md aus Section[] (<code>build.ts:29</code>)</li></ul></details>',33)])])}const g=t(d,[["render",a]]);export{p as __pageData,g as default};
